// CRC-32 Calculator
module RefModule (  
    input wire clk,  
    input wire rst,  
    input wire en,  
    input wire D,  
    output reg Q  
);  
always @(posedge clk or posedge rst) begin  
    if (rst) begin  
        Q <= 0;  
    end else if (en) begin  
        Q <= D;  
    end  
end  
endmodule
